dir.commands:
    &XMLWhenFilterLoading;
    &XMLWhenFilterClosing;




declare @k varchar(256)
select @k = rtrim(dvcs_yn) + ', ' + rtrim(bp_yn) + ', ' + rtrim(kh_yn) + ', ' + rtrim(tk_yn) + ', ' + rtrim(sl_yn) + ', ' + rtrim(tien_yn) + ', ' + rtrim(loai_ct_yn) from sodmloaiduyet where loai_duyet = @loai_duyet
select '' as field, '' as message, 'set$VoucherFilter$(this, [' + rtrim(@k) + ']);' as script
return

script.text:
      &JavascriptReportFilter;
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(sender) {sender.add_onResponseComplete(on$Filter$ResponseComplete);}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function onChange$Filter$SOApprovalCategory$Function(o) {o.parentForm.request('SOApprovingType', 'SOApprovingType', ['loai_duyet']);}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, g = f.grid, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var k = new Array();
      g._approvalType = f.getItemValue('loai_duyet');
      g._approvalName = f.getItemValue('ten_loai_duyet%l');
      Array.add(k, {Name: 'loai_duyet', Opr: '=', Value: g._approvalType, Type: 'String', Ignore: false});
      g.set_externalKey(k);
      g._alterTitle = [null, [['%c', g._approvalType + ' - ' + g._approvalName, true]]];
      break;
    default:
      break;
  }
}

function set$VoucherFilter$(sender, k) {
  var g = sender.grid;
  g._dvcs_yn = k[0];
  g._bp_yn = k[1];
  g._kh_yn = k[2];
  g._tk_yn = k[3];
  g._sl_yn = k[4];
  g._tien_yn = k[5];
  g._loai_ct_yn = k[6];
  g._hiddenFields = [
    {Fields: 'dvcs', Value: !k[0]},
    {Fields: 'ma_bp', Value: !k[1]},
    {Fields: 'nh_kh1, nh_kh2, nh_kh3', Value: !k[2]},
    {Fields: 'tk', Value: !k[3]},
    {Fields: 'so_luong', Value: !k[4]},
    {Fields: 'tien', Value: !k[5]},
    {Fields: 'loai_ct', Value: !k[6]}
  ];
  remove$GridReport$Filter(g);
}
/* </flatten> */
